PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?novel ?novelLabel WHERE {
  wd:Q201937 wdt:P50 ?novel .
  ?novel wdt:P31 wd:Q21123402 .
  {
    ?adaptation wdt:P140 ?novel .
    ?adaptation wdt:P31 wd:Q11424 .
  } UNION {
    ?adaptation wdt:P140 ?novel .
    ?adaptation wdt:P31 wd:Q28302 .
  }
  OPTIONAL {
    ?novel rdfs:label ?novelLabel .
    FILTER(LANG(?novelLabel) = "en")
  }
}

